#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

#include "../common.h"
#include "../util/timer/timer.h"

__global__ void kernel_cpu_kernel(
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans)
{
    int bid = blockIdx.x;
    if (bid >= count) return;

    int threadsPerBlock = order < 1024 ? order : 1024;

    for (int i = 0; i < maxheight; i++) {
        for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
            int key_left = knodes[currKnode[bid]].keys[thid];
            int key_right = knodes[currKnode[bid]].keys[thid + 1];
            if (key_left <= keys[bid] && key_right > keys[bid]) {
                if (knodes[offset[bid]].indices[thid] < knodes_elem) {
                    offset[bid] = knodes[offset[bid]].indices[thid];
                }
            }
        }
        __syncthreads();
        currKnode[bid] = offset[bid];
    }

    for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
        if (keys[bid] == knodes[currKnode[bid]].keys[thid]) {
            ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
        }
    }
}

void kernel_cpu(
    int cores_arg,
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans)
{
    long long time0 = get_time();

    int threadsPerBlock = order < 1024 ? order : 1024;

    long long time1 = get_time();

    // Launch one block per query, threads per block = threadsPerBlock
    kernel_cpu_kernel<<<count, threadsPerBlock>>>(
        records,
        knodes,
        knodes_elem,
        order,
        maxheight,
        count,
        currKnode,
        offset,
        keys,
        ans);

    cudaDeviceSynchronize();

    long long time2 = get_time();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
    printf("%15.12f s, %15.12f %% : MCPU: SET DEVICE\n",
           (float)(time1 - time0) / 1000000,
           (float)(time1 - time0) / (float)(time2 - time0) * 100);
    printf("%15.12f s, %15.12f %% : CPU/MCPU: KERNEL\n",
           (float)(time2 - time1) / 1000000,
           (float)(time2 - time1) / (float)(time2 - time0) * 100);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time2 - time0) / 1000000);
}

