#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_cpu_2.h"

__global__ void kernel_cpu_2_kernel(
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    long *lastKnode,
    long *offset_2,
    int *start,
    int *end,
    int *recstart,
    int *reclength)
{
    int bid = blockIdx.x;
    if (bid >= count) return;

    int threadsPerBlock = 1024 > order ? order : 1024;

    for (int i = 0; i < maxheight; i++) {
        for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
            int key_curr_left = knodes[currKnode[bid]].keys[thid];
            int key_curr_right = knodes[currKnode[bid]].keys[thid + 1];
            if (key_curr_left <= start[bid] && start[bid] < key_curr_right) {
                if (knodes_elem > knodes[currKnode[bid]].indices[thid]) {
                    offset[bid] = knodes[currKnode[bid]].indices[thid];
                }
            }
            int key_last_left = knodes[lastKnode[bid]].keys[thid];
            int key_last_right = knodes[lastKnode[bid]].keys[thid + 1];
            if (end[bid] >= key_last_left && end[bid] < key_last_right) {
                if (knodes_elem > knodes[lastKnode[bid]].indices[thid]) {
                    offset_2[bid] = knodes[lastKnode[bid]].indices[thid];
                }
            }
        }
        __syncthreads();
        currKnode[bid] = offset[bid];
        lastKnode[bid] = offset_2[bid];
    }

    for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
        if (knodes[currKnode[bid]].keys[thid] == start[bid]) {
            recstart[bid] = knodes[currKnode[bid]].indices[thid];
        }
    }

    for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
        if (knodes[lastKnode[bid]].keys[thid] == end[bid]) {
            reclength[bid] = knodes[lastKnode[bid]].indices[thid] - recstart[bid] + 1;
        }
    }
}

void kernel_cpu_2(
    int cores_arg,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    long *lastKnode,
    long *offset_2,
    int *start,
    int *end,
    int *recstart,
    int *reclength)
{
    long long time0 = get_time();

    int threadsPerBlock = 1024 > order ? order : 1024;

    long long time1 = get_time();

    kernel_cpu_2_kernel<<<count, threadsPerBlock>>>(
        knodes,
        knodes_elem,
        order,
        maxheight,
        count,
        currKnode,
        offset,
        lastKnode,
        offset_2,
        start,
        end,
        recstart,
        reclength);

    cudaDeviceSynchronize();

    long long time2 = get_time();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
    printf("%15.12f s, %15.12f %% : MCPU: SET DEVICE\n",
           (float)(time1 - time0) / 1000000,
           (float)(time1 - time0) / (float)(time2 - time0) * 100);
    printf("%15.12f s, %15.12f %% : CPU/MCPU: KERNEL\n",
           (float)(time2 - time1) / 1000000,
           (float)(time2 - time1) / (float)(time2 - time0) * 100);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time2 - time0) / 1000000);
}

